# Gerado a partir de spark/sql/ (pasta sql removida; conteúdo embutido para paridade com dbt).

PIPELINE_SQL = "-- Grain: 1 linha = 1 código CID (deduplicado por cd_doenca_cid)\n-- Fonte: silver_context.procedimento via glue_catalog.silver_context.procedimento\n-- Camada: Gold | Tipo: SCD1 (códigos CID são estáveis)\n-- Dimensão conformada — compartilhada entre fatos assistenciais e financeiros\n-- ⚠️  Apenas código disponível — sem descrição no Silver-Context atual.\n--     Enriquecer com seed de tabela CID quando disponível.\n\n\nWITH source AS (\n    SELECT * FROM glue_catalog.silver_context.procedimento\n    WHERE cd_doenca_cid <> -1\n)\n\n-- Pega o estado mais recente de cada CID via _context_processed_at\n, cid_ranked AS (\n    SELECT\n        cd_doenca_cid\n      , ROW_NUMBER() OVER (\n            PARTITION BY cd_doenca_cid\n            ORDER BY _context_processed_at DESC\n        ) AS rn\n    FROM source\n)\n\n, final AS (\n    SELECT\n          md5(concat_ws('||', coalesce(cast(cd_doenca_cid as string), '_dbt_utils_surrogate_key_null_')))       AS sk_cid\n        , cd_doenca_cid                                                   AS nk_cid\n        , FROM_UTC_TIMESTAMP(CURRENT_TIMESTAMP(), 'America/Sao_Paulo')   AS _gold_loaded_at\n    FROM cid_ranked\n    WHERE rn = 1\n)\n\nSELECT * FROM final\n"
